module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const color = args.color || 'var(--accent-color)';
const align = (args.align || 'left').toLowerCase();
const textAlign = align === 'center' ? 'center' : align === 'right' ? 'right' : 'left';
const shadow = !(args.shadow === false || args.shadow === 'false');
const radius = parseFloat(args.radius);
const icon = (args.icon && String(args.icon).trim()) ? `<span class="card-icon">${esc(String(args.icon).trim())}</span> ` : '';
const titleStr = sections[0] ? sections[0].trim() : '';
const bodyStr = sections[1] ? sections[1].trim() : '';
let cardStyle = '';
if (Number.isFinite(radius) && radius >= 0) cardStyle = ` style="--card-r:${radius}px;"`;
const cls = `mdp-mod-card${shadow ? '' : ' mdp-card-flat'}`;
return `\n\n<div class="${cls}"${cardStyle}><div class="card-header" style="background-color: ${color}; text-align: ${textAlign};">\n\n${icon}${titleStr}\n\n</div><div class="card-body">\n\n${bodyStr}\n\n</div></div>\n\n`;
